export enum RiskLevel {
  LOW = 'LOW',
  MEDIUM = 'MEDIUM',
  HIGH = 'HIGH',
  UNKNOWN = 'UNKNOWN'
}

export interface GroundingSource {
  title: string;
  uri: string;
}

export interface AnalysisResult {
  headline: string;
  summary: string;
  riskFactor: RiskLevel;
  riskScore: number; // 0 to 100
  reasons: string[];
  verdict: string;
  sources: GroundingSource[];
}

export interface AnalysisState {
  isAnalyzing: boolean;
  result: AnalysisResult | null;
  error: string | null;
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { AnalysisResult, RiskLevel } from "../types";

const API_KEY = process.env.API_KEY || "";

export const analyzeContent = async (
  text?: string,
  imageUrl?: string
): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const systemInstruction = `
    You are an expert fact-checker and media forensic specialist designed for elderly users. 
    Your goal is to analyze news text or images/video frames to determine if they are fake, misleading, or authentic.
    Provide a "Risk Factor" score from 0 (Safe) to 100 (Dangerous/Fake).
    Use simple, clear language. Avoid technical jargon.
    Crucially, use Google Search to find real-world evidence for any claims made.
  `;

  const prompt = text 
    ? `Analyze this news claim: "${text}"`
    : `Analyze this image/video frame for authenticity. Check for AI generation, manipulation, or known fake viral content.`;

  const contents: any = {
    parts: []
  };

  if (text) {
    contents.parts.push({ text: prompt });
  }

  if (imageUrl) {
    const base64Data = imageUrl.split(',')[1];
    contents.parts.push({
      inlineData: {
        mimeType: 'image/jpeg',
        data: base64Data
      }
    });
    if (!text) {
      contents.parts.push({ text: prompt });
    }
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: contents,
    config: {
      systemInstruction,
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          headline: { type: Type.STRING, description: "A catchy title for the analysis" },
          summary: { type: Type.STRING, description: "One sentence summary of the news" },
          riskFactor: { type: Type.STRING, enum: ["LOW", "MEDIUM", "HIGH"], description: "Overall risk level" },
          riskScore: { type: Type.NUMBER, description: "Score from 0 to 100" },
          reasons: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "List of simple reasons why it is risky or safe"
          },
          verdict: { type: Type.STRING, description: "The final simple verdict (e.g., 'This is definitely fake')" },
        },
        required: ["headline", "summary", "riskFactor", "riskScore", "reasons", "verdict"]
      }
    }
  });

  const jsonResult = JSON.parse(response.text || "{}");

  // Extract sources from grounding metadata
  const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  const sources = groundingChunks
    .filter((chunk: any) => chunk.web)
    .map((chunk: any) => ({
      title: chunk.web.title,
      uri: chunk.web.uri
    }));

  return {
    ...jsonResult,
    sources: sources.slice(0, 3) // Take top 3 sources
  };
};

import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer } from 'recharts';
import { RiskLevel } from '../types';

interface GaugeProps {
  score: number;
  level: RiskLevel;
}

const Gauge: React.FC<GaugeProps> = ({ score, level }) => {
  const data = [
    { value: score },
    { value: 100 - score },
  ];

  const getColor = (lvl: RiskLevel) => {
    switch (lvl) {
      case RiskLevel.LOW: return '#22c55e'; // Green
      case RiskLevel.MEDIUM: return '#eab308'; // Yellow
      case RiskLevel.HIGH: return '#ef4444'; // Red
      default: return '#94a3b8';
    }
  };

  const color = getColor(level);

  return (
    <div className="relative w-full h-48 flex items-center justify-center">
      <ResponsiveContainer width="100%" height="100%">
        <PieChart>
          <Pie
            data={data}
            cx="50%"
            cy="80%"
            startAngle={180}
            endAngle={0}
            innerRadius={60}
            outerRadius={90}
            paddingAngle={0}
            dataKey="value"
          >
            <Cell fill={color} stroke="none" />
            <Cell fill="#e2e8f0" stroke="none" />
          </Pie>
        </PieChart>
      </ResponsiveContainer>
      <div className="absolute top-[60%] flex flex-col items-center">
        <span className="text-3xl font-bold" style={{ color }}>{score}%</span>
        <span className="text-sm font-semibold uppercase tracking-wider text-slate-500">Risk Factor</span>
      </div>
    </div>
  );
};

export default Gauge;

import React from 'react';
import { AnalysisResult, RiskLevel } from '../types';
import Gauge from './Gauge';
import { ShieldCheck, AlertTriangle, XCircle, ExternalLink, RefreshCw } from 'lucide-react';

interface AnalysisViewProps {
  result: AnalysisResult;
  onReset: () => void;
}

const AnalysisView: React.FC<AnalysisViewProps> = ({ result, onReset }) => {
  const getIcon = () => {
    switch (result.riskFactor) {
      case RiskLevel.LOW: return <ShieldCheck className="w-12 h-12 text-green-500" />;
      case RiskLevel.MEDIUM: return <AlertTriangle className="w-12 h-12 text-yellow-500" />;
      case RiskLevel.HIGH: return <XCircle className="w-12 h-12 text-red-500" />;
      default: return null;
    }
  };

  const getVerdictBg = () => {
    switch (result.riskFactor) {
      case RiskLevel.LOW: return 'bg-green-50 border-green-200 text-green-800';
      case RiskLevel.MEDIUM: return 'bg-yellow-50 border-yellow-200 text-yellow-800';
      case RiskLevel.HIGH: return 'bg-red-50 border-red-200 text-red-800';
      default: return 'bg-slate-50 border-slate-200 text-slate-800';
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex flex-col items-center text-center p-6 bg-white rounded-3xl shadow-sm border border-slate-100">
        {getIcon()}
        <h2 className="mt-4 text-2xl font-bold text-slate-800">{result.headline}</h2>
        <p className="mt-2 text-lg text-slate-600 leading-relaxed">{result.summary}</p>
      </div>

      <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 overflow-hidden">
        <Gauge score={result.riskScore} level={result.riskFactor} />

        <div className={`mt-6 p-4 rounded-2xl border ${getVerdictBg()} text-center`}>
          <span className="text-xl font-bold">{result.verdict}</span>
        </div>
      </div>

      <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100">
        <h3 className="text-xl font-bold text-slate-800 mb-4">Why is this risk score given?</h3>
        <ul className="space-y-4">
          {result.reasons.map((reason, idx) => (
            <li key={idx} className="flex items-start gap-3">
              <div className="mt-1.5 w-2 h-2 rounded-full bg-blue-500 flex-shrink-0" />
              <p className="text-lg text-slate-700 leading-snug">{reason}</p>
            </li>
          ))}
        </ul>
      </div>

      {result.sources.length > 0 && (
        <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100">
          <h3 className="text-xl font-bold text-slate-800 mb-4">Trusted Sources Found:</h3>
          <div className="space-y-3">
            {result.sources.map((source, idx) => (
              <a
                key={idx}
                href={source.uri}
                target="_blank"
                rel="noopener noreferrer"
                className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl hover:bg-slate-100 transition-colors group"
              >
                <span className="font-medium text-slate-700 line-clamp-1">{source.title}</span>
                <ExternalLink className="w-5 h-5 text-slate-400 group-hover:text-blue-500" />
              </a>
            ))}
          </div>
        </div>
      )}

      <button
        onClick={onReset}
        className="w-full py-5 bg-slate-800 text-white rounded-3xl font-bold text-xl flex items-center justify-center gap-3 hover:bg-slate-900 transition-all active:scale-95 shadow-lg"
      >
        <RefreshCw className="w-6 h-6" />
        Check Another One
      </button>
    </div>
  );
};

export default AnalysisView;

import React, { useState, useRef } from 'react';
import { analyzeContent } from './services/geminiService';
import { AnalysisState } from './types';
import AnalysisView from './components/AnalysisView';
import { Search, Upload, Newspaper, Video, AlertCircle, Loader2, ArrowRight } from 'lucide-react';

const App: React.FC = () => {
  const [inputText, setInputText] = useState('');
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [analysisState, setAnalysisState] = useState<AnalysisState>({
    isAnalyzing: false,
    result: null,
    error: null,
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleTextChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setInputText(e.target.value);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        setSelectedImage(event.target?.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const runAnalysis = async () => {
    if (!inputText && !selectedImage) {
      setAnalysisState(prev => ({ ...prev, error: "Please provide some text or an image to analyze." }));
      return;
    }

    setAnalysisState({ isAnalyzing: true, result: null, error: null });

    try {
      const result = await analyzeContent(inputText, selectedImage || undefined);
      setAnalysisState({ isAnalyzing: false, result, error: null });
    } catch (err) {
      console.error(err);
      setAnalysisState({ 
        isAnalyzing: false, 
        result: null, 
        error: "Something went wrong. Please try again later." 
      });
    }
  };

  const reset = () => {
    setInputText('');
    setSelectedImage(null);
    setAnalysisState({ isAnalyzing: false, result: null, error: null });
  };

  return (
    <div className="min-h-screen max-w-2xl mx-auto px-4 py-8 pb-20">
      {/* Header */}
      <header className="mb-10 text-center">
        <div className="inline-flex items-center justify-center w-16 h-16 bg-blue-600 rounded-2xl mb-4 shadow-xl shadow-blue-200">
          <Newspaper className="text-white w-8 h-8" />
        </div>
        <h1 className="text-4xl font-extrabold text-slate-900 tracking-tight">Vigilant</h1>
        <p className="text-xl text-slate-500 mt-2 font-medium">Your Wise News Guardian</p>
      </header>

      {!analysisState.result ? (
        <div className="space-y-8 animate-in fade-in duration-500">
          {/* Instructions for Seniors */}
          <div className="bg-blue-50 border border-blue-100 p-6 rounded-3xl">
            <h2 className="text-xl font-bold text-blue-900 mb-2">How to use:</h2>
            <p className="text-lg text-blue-800 leading-snug">
              Paste a suspicious message, news link, or upload a photo of a news clip. I'll tell you if it's safe to believe!
            </p>
          </div>

          {/* Text Input */}
          <div className="space-y-4">
            <div className="flex items-center gap-2 mb-2 ml-1">
              <Search className="w-5 h-5 text-slate-400" />
              <label className="text-xl font-bold text-slate-700">Paste Text or Link</label>
            </div>
            <textarea
              className="w-full h-40 p-5 rounded-3xl border-2 border-slate-200 bg-white text-xl focus:border-blue-500 focus:ring-4 focus:ring-blue-100 transition-all outline-none resize-none shadow-sm"
              placeholder="Example: 'Did you hear about the free health kits?'"
              value={inputText}
              onChange={handleTextChange}
            />
          </div>

          {/* Media Upload */}
          <div className="space-y-4">
            <div className="flex items-center gap-2 mb-2 ml-1">
              <Video className="w-5 h-5 text-slate-400" />
              <label className="text-xl font-bold text-slate-700">Or Upload a Photo/Video Clip</label>
            </div>
            <div 
              onClick={() => fileInputRef.current?.click()}
              className={`relative h-48 rounded-3xl border-2 border-dashed border-slate-300 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-50 transition-colors ${selectedImage ? 'border-blue-400 bg-blue-50' : ''}`}
            >
              {selectedImage ? (
                <div className="relative w-full h-full p-2">
                  <img src={selectedImage} alt="Preview" className="w-full h-full object-cover rounded-2xl" />
                  <div className="absolute inset-0 bg-black/40 rounded-2xl flex items-center justify-center opacity-0 hover:opacity-100 transition-opacity">
                    <p className="text-white font-bold text-lg">Tap to change</p>
                  </div>
                </div>
              ) : (
                <>
                  <Upload className="w-12 h-12 text-slate-400 mb-2" />
                  <p className="text-lg font-semibold text-slate-500">Tap to select photo</p>
                </>
              )}
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                className="hidden" 
                accept="image/*,video/*"
              />
            </div>
          </div>

          {/* Error Message */}
          {analysisState.error && (
            <div className="flex items-center gap-3 p-4 bg-red-50 border border-red-100 rounded-2xl text-red-700">
              <AlertCircle className="w-6 h-6 flex-shrink-0" />
              <p className="font-semibold text-lg">{analysisState.error}</p>
            </div>
          )}

          {/* Action Button */}
          <button
            onClick={runAnalysis}
            disabled={analysisState.isAnalyzing || (!inputText && !selectedImage)}
            className={`w-full py-6 rounded-3xl font-bold text-2xl flex items-center justify-center gap-4 shadow-xl transition-all active:scale-95 disabled:opacity-50 disabled:active:scale-100 ${
              analysisState.isAnalyzing ? 'bg-slate-100 text-slate-400' : 'bg-blue-600 text-white hover:bg-blue-700'
            }`}
          >
            {analysisState.isAnalyzing ? (
              <>
                <Loader2 className="w-8 h-8 animate-spin" />
                Checking Carefully...
              </>
            ) : (
              <>
                Analyze Now
                <ArrowRight className="w-8 h-8" />
              </>
            )}
          </button>
        </div>
      ) : (
        <AnalysisView result={analysisState.result} onReset={reset} />
      )}

      {/* Footer Info */}
      <footer className="mt-12 pt-8 border-t border-slate-100 text-center text-slate-400 pb-10">
        <p className="text-sm font-medium uppercase tracking-widest">Built for Elders with ❤️</p>
        <p className="text-xs mt-2 px-10">Verification powered by Gemini AI with Google Search integration.</p>
      </footer>
    </div>
  );
};

export default App;

