  title: string;
  uri: string;
}

export interface AnalysisResult {
  headline: string;
  summary: string;
  riskFactor: RiskLevel;
  riskScore: number;
  reasons: string[];
  verdict: string;
  careMessage: string; // New field for elder-friendly warnings
