import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { AnalysisResult, RiskLevel, SecurityModule } from "../types";

const API_KEY = process.env.API_KEY || "";

export const analyzeSecurityContent = async (
  module: SecurityModule,
  text?: string,
  imageUrl?: string
): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  let systemInstruction = `
    You are "Raksha Sutra," a respectful, caring, and wise digital guardian for elders. 
    Your tone is warm, protective, and patient—like a devoted family member.
    Your goal is to protect the user from digital harm.
  `;

  let specificTask = "";

  switch (module) {
    case SecurityModule.NEWS:
      specificTask = "Analyze this news claim or video frame for truth. Check for AI manipulation, fake rumors, or misleading information.";
      break;
    case SecurityModule.EMAIL:
      specificTask = "Analyze this email content for phishing signs. Look for fake urgency, suspicious requests for personal info, and hidden scam patterns.";
      break;
    case SecurityModule.URL:
      specificTask = "Analyze this website link. Check if it's a fake version of a real site, a known scam link, or a dangerous address.";
      break;
    case SecurityModule.PAYMENT:
      specificTask = "Analyze this payment situation or request. Determine if it's a scam (like fake electricity bills, prize winnings, or family emergencies).";
      break;
  }

  systemInstruction += `\n\nTask: ${specificTask}
    If the risk is HIGH, provide a very warm 'careMessage' explaining that you are worried and they should stop immediately.
    Use simple language. Provide a riskScore from 0 to 100.
    Always use Google Search to verify the latest threats and news.
  `;

  const prompt = text 
    ? `Dear Raksha Sutra, please look at this for me: "${text}"`
    : `Dear Raksha Sutra, I have an image of this. Is it safe for me?`;

  const contents: any = { parts: [] };
  if (text) contents.parts.push({ text: prompt });
  if (imageUrl) {
    const base64Data = imageUrl.split(',')[1];
    contents.parts.push({
      inlineData: { mimeType: 'image/jpeg', data: base64Data }
    });
    if (!text) contents.parts.push({ text: prompt });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: contents,
    config: {
      systemInstruction,
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          headline: { type: Type.STRING },
          summary: { type: Type.STRING },
          riskFactor: { type: Type.STRING, enum: ["LOW", "MEDIUM", "HIGH"] },
          riskScore: { type: Type.NUMBER },
          reasons: { type: Type.ARRAY, items: { type: Type.STRING } },
          verdict: { type: Type.STRING },
          careMessage: { type: Type.STRING }
        },
        required: ["headline", "summary", "riskFactor", "riskScore", "reasons", "verdict", "careMessage"]
      }
    }
  });

  const jsonResult = JSON.parse(response.text || "{}");
  const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  const sources = groundingChunks
    .filter((chunk: any) => chunk.web)
    .map((chunk: any) => ({
      title: chunk.web.title,
      uri: chunk.web.uri
    }));

  return { ...jsonResult, sources: sources.slice(0, 3) };
};

