import React from 'react';
import { AnalysisResult, RiskLevel } from '../types';
import Gauge from './Gauge';
import { Heart, AlertCircle, CheckCircle2, ExternalLink, RefreshCw, Info, ShieldAlert } from 'lucide-react';

interface AnalysisViewProps {
  result: AnalysisResult;
  onReset: () => void;
}

const AnalysisView: React.FC<AnalysisViewProps> = ({ result, onReset }) => {
  const getHeaderStyle = () => {
    switch (result.riskFactor) {
      case RiskLevel.LOW: return { icon: <CheckCircle2 className="w-20 h-20 text-emerald-500" />, bg: 'bg-emerald-50/50', border: 'border-emerald-200' };
      case RiskLevel.MEDIUM: return { icon: <AlertCircle className="w-20 h-20 text-amber-500" />, bg: 'bg-amber-50/50', border: 'border-amber-200' };
      case RiskLevel.HIGH: return { icon: <ShieldAlert className="w-20 h-20 text-rose-500" />, bg: 'bg-rose-50/50', border: 'border-rose-200' };
      default: return { icon: <Info className="w-20 h-20 text-slate-500" />, bg: 'bg-slate-50/50', border: 'border-slate-200' };
    }
  };

  const { icon, bg, border } = getHeaderStyle();

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-10 duration-700 pb-20">
      {/* Care Message - Prominent for Risk */}
      {result.riskFactor !== RiskLevel.LOW && (
        <div className="bg-rose-600 p-8 rounded-[2.5rem] shadow-2xl text-white flex gap-6 items-start relative overflow-hidden">
          <div className="p-4 bg-white/20 backdrop-blur-md rounded-3xl flex-shrink-0 relative z-10">
            <Heart className="w-10 h-10 fill-white text-white" />
          </div>
          <div className="relative z-10">
            <h3 className="text-2xl font-black mb-2">Grandchild's Message</h3>
            <p className="text-xl leading-relaxed font-bold italic opacity-95">
              "{result.careMessage}"
            </p>
          </div>
          <Heart className="absolute -bottom-10 -right-10 w-48 h-48 text-white/10 rotate-12" />
        </div>
      )}

      {/* Main Analysis Results Card */}
      <div className={`p-8 lg:p-12 ${bg} border-2 ${border} rounded-[3rem] shadow-xl text-center relative overflow-hidden backdrop-blur-sm`}>
        <div className="flex justify-center mb-6">{icon}</div>
        <h2 className="text-4xl font-black text-slate-800 leading-tight mb-4">{result.headline}</h2>
        <p className="text-2xl text-slate-700 leading-relaxed font-semibold max-w-2xl mx-auto">
          {result.summary}
        </p>
        <div className="mt-10 h-1 w-32 bg-slate-200 rounded-full mx-auto"></div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Safety Gauge */}
        <div className="bg-white rounded-[3rem] p-10 shadow-xl border border-slate-100 flex flex-col items-center">
          <Gauge score={result.riskScore} level={result.riskFactor} />
          <div className={`mt-10 w-full p-6 rounded-3xl text-center border-2 shadow-lg ${
            result.riskFactor === RiskLevel.LOW ? 'bg-emerald-500 border-emerald-400 text-white' : 
            result.riskFactor === RiskLevel.MEDIUM ? 'bg-amber-500 border-amber-400 text-white' : 
            'bg-rose-500 border-rose-400 text-white'
          }`}>
            <span className="text-2xl font-black">{result.verdict}</span>
          </div>
        </div>

        {/* Reasons List */}
        <div className="bg-white rounded-[3rem] p-10 shadow-xl border border-slate-100">
          <h3 className="text-2xl font-black text-slate-800 mb-8 flex items-center gap-3">
            <ShieldCheck className="w-8 h-8 text-rose-500" />
            Safety Analysis
          </h3>
          <ul className="space-y-6">
            {result.reasons.map((reason, idx) => (
              <li key={idx} className="flex items-start gap-4 group">
                <div className="mt-2 w-4 h-4 rounded-full bg-rose-100 border-2 border-rose-500 flex-shrink-0 group-hover:scale-125 transition-transform" />
                <p className="text-xl text-slate-700 leading-snug font-medium">{reason}</p>
              </li>
            ))}
          </ul>
        </div>
      </div>

      {/* Sources */}
      {result.sources.length > 0 && (
        <div className="bg-slate-900 rounded-[3rem] p-10 text-white shadow-2xl">
          <h3 className="text-2xl font-black mb-8 flex items-center gap-3">
            <Globe className="w-8 h-8 text-rose-500" />
            Verified Online Evidence
          </h3>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            {result.sources.map((source, idx) => (
              <a
                key={idx}
                href={source.uri}
                target="_blank"
                rel="noopener noreferrer"
                className="flex items-center justify-between p-6 bg-white/5 border border-white/10 rounded-3xl hover:bg-white/10 hover:border-rose-500/50 transition-all group"
              >
                <span className="text-lg font-black text-white/90 line-clamp-1">{source.title}</span>
                <ExternalLink className="w-6 h-6 text-rose-500 flex-shrink-0 group-hover:scale-110 transition-transform" />
              </a>
            ))}
          </div>
        </div>
      )}

      <button
        onClick={onReset}
        className="w-full py-8 bg-rose-500 text-white rounded-[2.5rem] font-black text-3xl flex items-center justify-center gap-4 hover:bg-rose-600 transition-all active:scale-95 shadow-2xl shadow-rose-200"
      >
        <RefreshCw className="w-8 h-8" />
        Protect Something Else
      </button>
    </div>
  );
};

