import { 
  Heart, Newspaper, Video, AlertCircle, Loader2, ArrowRight, 
  Mail, Link as LinkIcon, CreditCard, ShieldCheck, ChevronLeft, Upload, Search,
  PhoneCall, ExternalLink, Globe, ShieldAlert, BookOpen, AlertOctagon, Info
} from 'lucide-react';

const App: React.FC = () => {
  const [currentModule, setCurrentModule] = useState<SecurityModule>(SecurityModule.HOME);
  const [inputText, setInputText] = useState('');
