import React from 'react';
import { AnalysisResult, RiskLevel } from '../types';
import Gauge from './Gauge';
import { Heart, AlertCircle, CheckCircle2, ExternalLink, RefreshCw, Info, ShieldAlert, ShieldCheck, Globe } from 'lucide-react';

interface AnalysisViewProps {
  result: AnalysisResult;
  onReset: () => void;
}

const AnalysisView: React.FC = ({ result, onReset }) => {
  const getHeaderStyle = () => {
    switch (result.riskFactor) {
      case RiskLevel.LOW: return { icon: <CheckCircle2 className="w-20 h-20 text-emerald-600" />, bg: 'bg-emerald-50/40', border: 'border-emerald-100' };
      case RiskLevel.MEDIUM: return { icon: <AlertCircle className="w-20 h-20 text-amber-600" />, bg: 'bg-amber-50/40', border: 'border-amber-100' };
      case RiskLevel.HIGH: return { icon: <ShieldAlert className="w-20 h-20 text-rose-600" />, bg: 'bg-rose-50/40', border: 'border-rose-100' };
      default: return { icon: <Info className="w-20 h-20 text-slate-600" />, bg: 'bg-slate-50/40', border: 'border-slate-100' };
    }
  };

  const { icon, bg, border } = getHeaderStyle();

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-6 duration-700 pb-24">
      {/* Care Message - Muted for eyesight comfort */}
      {result.riskFactor !== RiskLevel.LOW && (
        <div className="bg-emerald-800 p-8 rounded-[2.5rem] shadow-lg text-white flex gap-6 items-start relative overflow-hidden">
          <div className="p-4 bg-white/10 backdrop-blur-md rounded-3xl flex-shrink-0 relative z-10 border border-white/20">
            <Heart className="w-10 h-10 fill-white text-white" />
          </div>
          <div className="relative z-10">
            <h3 className="text-2xl font-black mb-2">Grandchild's Message</h3>
            <p className="text-xl leading-relaxed font-bold italic text-emerald-50/90">
              "{result.careMessage}"
            </p>
          </div>
        </div>
      )}

      {/* Main Analysis Results Card */}
      <div className={`p-8 lg:p-12 ${bg} border ${border} rounded-[3rem] shadow-sm text-center relative overflow-hidden backdrop-blur-md`}>
        <div className="flex justify-center mb-6">{icon}</div>
        <h2 className="text-4xl font-black text-slate-700 leading-tight mb-4">{result.headline}</h2>
        <p className="text-2xl text-slate-600 leading-relaxed font-semibold max-w-2xl mx-auto">
          {result.summary}
        </p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Safety Gauge */}
        <div className="bg-white rounded-[3rem] p-10 shadow-sm border border-slate-100 flex flex-col items-center">
          <Gauge score={result.riskScore} level={result.riskFactor} />
          <div className={`mt-8 w-full p-6 rounded-3xl text-center border shadow-sm ${
            result.riskFactor === RiskLevel.LOW ? 'bg-emerald-700 text-white border-emerald-800' : 
            result.riskFactor === RiskLevel.MEDIUM ? 'bg-amber-600 text-white border-amber-700' : 
            'bg-rose-700 text-white border-rose-800'
          }`}>
            <span className="text-2xl font-black">{result.verdict}</span>
          </div>
        </div>

        {/* Reasons List */}
        <div className="bg-white rounded-[3rem] p-10 shadow-sm border border-slate-100">
          <h3 className="text-2xl font-black text-slate-700 mb-8 flex items-center gap-3">
            <ShieldCheck className="w-8 h-8 text-emerald-700" />
            Safety Analysis
          </h3>
          <ul className="space-y-6">
            {result.reasons.map((reason, idx) => (
              <li key={idx} className="flex items-start gap-4 group">
                <div className="mt-2 w-4 h-4 rounded-full bg-emerald-100 border-2 border-emerald-600 flex-shrink-0" />
                <p className="text-xl text-slate-600 leading-snug font-medium">{reason}</p>
              </li>
            ))}
          </ul>
        </div>
      </div>

      {/* Sources */}
      {result.sources.length > 0 && (
        <div className="bg-slate-800 rounded-[3rem] p-10 text-white shadow-lg">
          <h3 className="text-2xl font-black mb-8 flex items-center gap-3">
            <Globe className="w-8 h-8 text-emerald-500" />
            Verified Online Evidence
          </h3>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            {result.sources.map((source, idx) => (
              <a
                key={idx}
                href={source.uri}
                target="_blank"
                rel="noopener noreferrer"
                className="flex items-center justify-between p-6 bg-white/5 border border-white/10 rounded-3xl hover:bg-white/10 hover:border-emerald-500/50 transition-all group"
              >
                <span className="text-lg font-black text-white/90 line-clamp-1">{source.title}</span>
                <ExternalLink className="w-6 h-6 text-emerald-500 flex-shrink-0 group-hover:scale-110 transition-transform" />
              </a>
            ))}
          </div>
        </div>
      )}

      <button
        onClick={onReset}
        className="w-full py-8 bg-emerald-700 text-white rounded-[2.5rem] font-black text-3xl flex items-center justify-center gap-4 hover:bg-emerald-800 transition-all active:scale-95 shadow-lg"
      >
        <RefreshCw className="w-8 h-8" />
        Analyze Something Else
      </button>
    </div>
  );
};

