                target="_blank"
                rel="noopener noreferrer"
                className="flex items-center justify-between p-4 bg-white/5 border border-white/10 rounded-2xl hover:bg-white/10 transition-all"
              >
                <span className="text-sm font-bold text-white/90 line-clamp-1">{source.title}</span>
                <ExternalLink className="w-4 h-4 text-indigo-400 flex-shrink-0" />
              </a>
            ))}
          </div>
        </div>
      )}

      <button
        onClick={onReset}
        className="w-full py-6 bg-indigo-600 text-white rounded-2xl font-bold text-xl flex items-center justify-center gap-3 hover:bg-indigo-700 shadow-lg transition-all active:scale-[0.98]"
      >
        <RefreshCw className="w-6 h-6" />
        Analyze New Content
      </button>
    </div>
  );
};

